def {{nama_fungsi}}(data):
    """Return dict mean, median, mode, stdev, min, max."""
    import statistics
    data = list(data)
    if not data:
        return {}
    result = {}
    result['count'] = len(data)
    result['mean'] = statistics.mean(data)
    result['median'] = statistics.median(data)
    try:
        result['mode'] = statistics.mode(data)
    except statistics.StatisticsError:
        result['mode'] = None
    result['stdev'] = statistics.stdev(data) if len(data) > 1 else 0.0
    result['min'] = min(data)
    result['max'] = max(data)
    return result

def {{nama_fungsi}}(data, window={{window}}, ema=False):
    """Return moving average list."""
    data = list(data)
    if not data or window <= 0:
        return []
    if ema:
        alpha = 2 / (window + 1)
        result = []
        ema_val = data[0]
        for x in data:
            ema_val = alpha * x + (1 - alpha) * ema_val
            result.append(ema_val)
        return result
    else:
        result = []
        for i in range(len(data) - window + 1):
            result.append(sum(data[i:i+window]) / window)
        return result

def {{nama_fungsi}}(n):
    """Factorial iterative."""
    if n < 0:
        raise ValueError('n must be >=0')
    result = 1
    for i in range(2, n+1):
        result *= i
    return result

def {{nama_fungsi}}(limit):
    """Yield primes up to limit."""
    if limit < 2:
        return
    sieve = bytearray(b'\x01') * (limit + 1)
    sieve[0:2] = b'\x00\x00'
    import math
    for p in range(2, int(math.isqrt(limit)) + 1):
        if sieve[p]:
            step = p
            start = p*p
            sieve[start:limit+1:step] = b'\x00' * ((limit - start)//step + 1)
    for i in range(2, limit+1):
        if sieve[i]:
            yield i

def {{nama_fungsi}}(a, b):
    """Return {'gcd': gcd, 'lcm': lcm}."""
    import math
    g = math.gcd(a, b)
    l = abs(a * b) // g if g else 0
    return {'gcd': g, 'lcm': l}

def {{nama_fungsi}}_nCk(n, k):
    """n choose k."""
    import math
    if hasattr(math, 'comb'):
        return math.comb(n, k)
    k = min(k, n-k)
    result = 1
    for i in range(1, k+1):
        result = result * (n - k + i) // i
    return result

def {{nama_fungsi}}_nPk(n, k):
    """n permute k."""
    import math
    if hasattr(math, 'perm'):
        return math.perm(n, k)
    result = 1
    for i in range(n, n-k, -1):
        result *= i
    return result

def {{nama_fungsi}}(n):
    """Yield fibonacci sampai n terms."""
    a, b = 0, 1
    for _ in range(n):
        yield a
        a, b = b, a + b
